const catalogResult = $input.item.json;
return {
  response: catalogResult.formatted_list || 'Products available',
  next_step: 'collecting_order_details',
  state_updates: { product_catalog: catalogResult.products }
};

// Load state and controller data
const rawState = $('Store Current State').first().json.state_data;
const state = typeof rawState === "string" ? JSON.parse(rawState) : rawState;

const controllerData = $('State Machine Controller').item.json;
const extractedData = controllerData.extracted_data || {};

console.log("📥 Extracted Data:", extractedData);
console.log("📥 State Available Slots:", state.available_slots);
console.log("📥 Incoming JSON:", $json);

// =====================================================================
// SHARED FIELDS
// =====================================================================
const addressRaw = state.delivery_address || state.last_order?.delivery_address || "";

// Address parser - New intelligent logic
function parseAddress(raw = "") {
  // Helper function to clean and normalize text
  function cleanText(text) {
    return text.trim().replace(/\s+/g, ' ');
  }

  // Helper function to check if a string is likely a postal code
  function isPostalCode(str) {
    return /^\d{4}$/.test(str.trim());
  }

  // Helper function to check if a string contains any number
  function hasNumber(str) {
    return /\d/.test(str);
  }

  // Split address by comma
  const parts = raw.split(',').map(part => cleanText(part)).filter(part => part.length > 0);

  let streetLine1 = '';
  let streetLine2 = '';
  let suburb = '';
  let city = '';
  let postalCode = '';

  if (parts.length === 0) {
    // Empty address
  } else {
    // Step 1: Working backwards, find 4-digit postal code
    let postalCodeIndex = -1;
    for (let i = parts.length - 1; i >= 0; i--) {
      if (isPostalCode(parts[i])) {
        postalCode = parts[i];
        postalCodeIndex = i;
        break;
      }
    }

    // Step 2: Working backwards from postal code, find first snippet with a number (last street line)
    let lastStreetIndex = -1;
    if (postalCodeIndex !== -1) {
      for (let i = postalCodeIndex - 1; i >= 0; i--) {
        if (hasNumber(parts[i])) {
          lastStreetIndex = i;
          break;
        }
      }
    }

    // Step 3: Check snippets between last street line and postal code
    if (lastStreetIndex !== -1 && postalCodeIndex !== -1) {
      const betweenCount = postalCodeIndex - lastStreetIndex - 1;

      if (betweenCount === 2) {
        // 2 snippets between: closest to code is City, next one is Suburb
        city = parts[postalCodeIndex - 1];
        suburb = parts[postalCodeIndex - 2];
      } else if (betweenCount === 1) {
        // Only 1 snippet: it's Suburb
        suburb = parts[postalCodeIndex - 1];
      }
      // If betweenCount is 0, no suburb/city (street line directly before postal code)

      // Step 4: Decide on street lines
      // All parts from beginning up to (but not including) suburb or postal code
      const endIndex = suburb ? parts.indexOf(suburb) : postalCodeIndex;
      const streetParts = parts.slice(0, endIndex);

      if (streetParts.length === 1) {
        // Only 1 snippet before suburb: it's streetLine1
        streetLine1 = streetParts[0];
      } else if (streetParts.length > 1) {
        // More than 1: closest to suburb is streetLine2, remainder is streetLine1
        streetLine2 = streetParts[streetParts.length - 1];
        streetLine1 = streetParts.slice(0, -1).join(', ');
      }
    } else if (parts.length > 0) {
      // Fallback: no clear structure found
      streetLine1 = parts[0];
    }
  }

  return { 
    street1: streetLine1, 
    street2: streetLine2, 
    suburb: suburb, 
    city: city, 
    postal: postalCode 
  };
}

const parsedAddress = parseAddress(addressRaw);

const orderId = "ORD-" + new Date().toISOString().replace(/[-:T.]/g, "").slice(0, 14);

// PRODUCT DETAILS (shared)
let productDetails = "";
const customerName = $('Store Current State').first().json.full_name || state.customer_data?.name || "";

// Try order_summary_json first (top level)
const orderSummaryRaw = $('Store Current State').first().json.order_summary_json;
if (orderSummaryRaw) {
  try {
    const orderSummary = JSON.parse(orderSummaryRaw);
    const lines = orderSummary?.lines || orderSummary;
    if (Array.isArray(lines) && lines.length > 0) {
      productDetails = lines
        .map(p => `${p.qty || p.Quantity || 1} × ${p.label || p.Description || ""}`)
        .join(", ");
    }
  } catch (e) {
    console.log("⚠️ Could not parse order_summary_json:", e.message);
  }
}

// Fallback to last_order.products if order_summary_json not available
if (!productDetails) {
  if (Array.isArray(state.last_order?.products)) {
    productDetails = state.last_order.products
      .map(p => `${p.quantity || 1} × ${p.description || ""}`)
      .join(", ");
  }
}

// =====================================================================
// 1. CUSTOM SLOT HANDLING (from Edit Fields2)
// =====================================================================
const customRow = $json.custom_row_index;
const customDate = $json.custom_date;
const customTime = $json.custom_time;

if (customRow !== undefined && customDate && customTime) {
  console.log("📌 Using CUSTOM SLOT booking");

  return {
    row_number: customRow,
    delivery_date: customDate,
    delivery_time: customTime,
    customer_name: customerName,
    phone_number: state.phone_number,
    email: state.customer_data?.email || "",
    street_address_1: parsedAddress.street1 || "",
    street_address_2: parsedAddress.street2 || "",
    suburb: parsedAddress.suburb || "",
    city: parsedAddress.city || "",
    postal_code: parsedAddress.postal || "",
    order_id: orderId,
    product_details: productDetails,
    delivery_instructions: "",
  };
}

// =====================================================================
// 2. LETTER-BASED SLOT HANDLING (A/B/C/D) - NEW TIMESLOT SYSTEM
// =====================================================================
if (extractedData.slot_letter) {
  const slotLetter = extractedData.slot_letter;
  console.log("📌 Using LETTER SLOT:", slotLetter);

  const selectedSlot = state.available_slots?.find(s =>
    (s.letter || s.label) === slotLetter
  );

  if (!selectedSlot) {
    throw new Error(`Slot ${slotLetter} not found in available slots`);
  }

  // NEW: delivery_time is now the timeslot (08:00-12:00 or 13:00-16:30)
  return {
    row_number: selectedSlot.row_index || selectedSlot.row_number || selectedSlot.first_row_index,
    delivery_date: selectedSlot.date,
    delivery_time: selectedSlot.timeslot, // Changed from 'time' to 'timeslot'
    customer_name: customerName,
    phone_number: state.phone_number,
    email: $input.first()?.json.state_data?.email || state.customer_data?.email || "",
    street_address_1: parsedAddress.street1 || "",
    street_address_2: parsedAddress.street2 || "",
    suburb: parsedAddress.suburb || "",
    city: parsedAddress.city || "",
    postal_code: parsedAddress.postal || "",
    order_id: orderId,
    product_details: productDetails,
    delivery_instructions: "",
  };
}

// =====================================================================
// 3. FALLBACK — NEITHER CUSTOM NOR LETTER SLOT PROVIDED
// =====================================================================
throw new Error("No valid slot information found (neither custom nor letter slot).");

// ===== GENERATE ORDER SUMMARY =====
const prepData = $input.item.json; // Get data from "Format Response" (previous node)

// Convert YYYY-MM-DD → DD/MM/YYYY
const formatDateDMY = (d) => {
  if (!d) return d;
  const [y, m, day] = d.split('-');
  return `${day}/${m}/${y}`;
};

// Build full address from the booking data
const fullAddress = [
  prepData.street_address_1,
  prepData.street_address_2,
  prepData.suburb,
  prepData.city,
  prepData.postal_code
].filter(part => part && part.trim()).join(', ');

// Build response
let response = '✅ Delivery booked!\n\n📋 *Order Summary:*\n\n';
response += `\n*Recipient:* ${prepData.customer_name}\n\n`;

response += '*Products:*\n';
const lines = (prepData.product_details || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

if (lines.length) {
  response += lines.map(l => `• ${l}`).join('\n') + '\n';
} else {
  response += '• (none)\n';
}

// ===== ONLY THIS LINE CHANGES =====
response += `\n*Delivery:* ${formatDateDMY(prepData.delivery_date)} at ${prepData.delivery_time}\n`;
// ==================================

response += `*Address:* ${fullAddress}\n\n`;

// ===== Get total from stored state =====
const storedState = $('Store Current State').first().json.state_data;
const state = typeof storedState === 'string' ? JSON.parse(storedState) : storedState;

const total = $('Store Current State')?.first()?.json.order_total || state?.last_order?.order_total || state?.last_order?.total || 0;

response += `*Total:* R${Number(total).toFixed(2)}\n\n`;

response += 'Reply:\nP - to pay\nD - to place a different order\nCancel - to cancel';

return {
  response,
  next_step: 'awaiting_payment_confirmation',
  state_updates: { 
    order_id: prepData.order_id,
    selected_slot: {
      date: prepData.delivery_date,
      time: prepData.delivery_time,
      row_index: prepData.row_number
    }
  }
};

// ===== PREP: PROCESS PAYMENT =====
const state = $('Parse State').item.json;

return {
  order_total: $input.first()?.json.state_data?.order_total || state.last_order?.total || state.last_order?.order_total || 0,
  customer_name: $input.first()?.json.state_data?.full_name || state.customer_data?.name || '',
  customer_email: $input.first()?.json.state_data?.email || state.customer_data?.email || '',
  customer_phone: $input.first()?.json.state_data?.phone_number || state.phone_number || '',
  order_reference: $input.first()?.json.state_data?.order_id || state.order_id || ''
};

// ===== FORMAT PAYMENT MESSAGE =====
const paymentResult = $input.item.json;
const state = $('Parse State').item.json;

let response = '💳 Payment Link Ready!\n\n';
response += 'Complete your payment:\n\n';
response += `${paymentResult.payment_url}\n\n`;
response += `Amount: R${$('Edit Fields1').first().json.order_total || 0}\n`;
response += `Order: ${state.order_id}\n\n`;
response += 'Payment link expires in 24 hours.';

return {
  response,
  next_step: 'awaiting_payment',
  state_updates: { payment_url: paymentResult.payment_url }
};

// No customer found
const whatsappNumber = $input.first().json.whatsapp_number;

return {
  customer_exists: false,
  whatsapp_number: whatsappNumber,
  has_previous_orders: false,
  customer_data: null,
  last_order: null,
  message: 'New customer - not found in Xero'
};

// Customer found - extract details
const xeroResponse = $input.first().json;
const contact = xeroResponse.Contacts[0];

// Extract customer information
const customerData = {
  contact_id: contact.ContactID,
  name: contact.Name,
  first_name: contact.FirstName || contact.Name.split(' ')[0],
  last_name: contact.LastName || '',
  email: contact.EmailAddress || '',
  phone: contact.Phones?.find(p => p.PhoneType === 'MOBILE')?.PhoneNumber || '',
  addresses: contact.Addresses || [],
  default_address: null
};

// Get default delivery address
if (customerData.addresses.length > 0) {
  const deliveryAddr = customerData.addresses.find(a => a.AddressType === 'POBOX') || customerData.addresses[0];
  if (deliveryAddr) {
    customerData.default_address = {
      line1: deliveryAddr.AddressLine1 || '',
      line2: deliveryAddr.AddressLine2 || '',
      city: deliveryAddr.City || '',
      region: deliveryAddr.Region || '',
      postal_code: deliveryAddr.PostalCode || '',
      country: deliveryAddr.Country || 'ZA'
    };
  }
}

return {
  customer_exists: true,
  customer_data: customerData,
  contact_id: contact.ContactID
};

// Parse last invoice/order
const customerData = $('Extract Customer Data').first().json.customer_data;
const invoiceResponse = $input.first().json;

let result = {
  customer_exists: true,
  customer_data: customerData,
  has_previous_orders: false,
  last_order: null
};

// Check if customer has any invoices
if (invoiceResponse.Invoices && invoiceResponse.Invoices.length > 0) {
  // Sort invoices by date (most recent first), then by invoice number (highest first)
  const sortedInvoices = [...invoiceResponse.Invoices].sort((a, b) => {
    // Compare dates first
    const dateA = new Date(a.DateString || a.Date);
    const dateB = new Date(b.DateString || b.Date);

    if (dateB.getTime() !== dateA.getTime()) {
      return dateB - dateA; // Descending order (newest first)
    }

    // If dates are equal, compare invoice numbers
    // Extract numeric part from invoice number (e.g., "INV-0018" -> 18)
    const numA = parseInt((a.InvoiceNumber || '').replace(/\D/g, '')) || 0;
    const numB = parseInt((b.InvoiceNumber || '').replace(/\D/g, '')) || 0;

    return numB - numA; // Descending order (highest invoice number first)
  });

  const lastInvoice = sortedInvoices[0];

  // Extract line items (products ordered)
  const products = [];
  if (lastInvoice.LineItems) {
    for (const line of lastInvoice.LineItems) {
      products.push({
        code: line.ItemCode || '',
        name: line.Item.Name,
        description: line.Description,
        quantity: line.Quantity,
        unit_price: line.UnitAmount,
        line_total: line.LineAmount,
        item_id: line.ItemID || null
      });
    }
  }

  result.has_previous_orders = true;
  result.last_order = {
    invoice_id: lastInvoice.InvoiceID,
    invoice_number: lastInvoice.InvoiceNumber,
    date: lastInvoice.DateString,
    total: lastInvoice.Total,
    status: lastInvoice.Status,
    products: products
  };
}

return result;

// Parse Xero response and create product list
const xeroResponse = $input.first().json;

if (!xeroResponse.Items || xeroResponse.Items.length === 0) {
  return {
    success: false,
    message: "No products found in Xero",
    products: [],
    formatted_list: "Sorry, no products are currently available."
  };
}

// helper can be here
function extractKg(name = "") {
  const m = String(name).match(/(\d+)\s*kg/i);
  return m ? parseInt(m[1], 10) : 9999; // non-KG items go to bottom
}

// Filter and format products
const products = [];
const letters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";

for (const item of xeroResponse.Items) {
  if (item.IsSold && item.SalesDetails?.UnitPrice) {
    let stockStatus = "Available";
    let stockInfo = "";

    if (item.IsTrackedAsInventory) {
      const qty = item.QuantityOnHand || 0;
      if (qty <= 0) continue;
      stockInfo = qty < 5 ? ` (${qty} left)` : ` (${qty} in stock)`;
    }

    products.push({
      letter: "", // assign after sorting
      code: item.Code,
      name: item.Name,
      price: item.SalesDetails.UnitPrice,
     // quantity_available: item.IsTrackedAsInventory ? (item.QuantityOnHand || 0) : 999,
      is_tracked: item.IsTrackedAsInventory || false,
      stock_status: stockStatus,
      stock_info: stockInfo,
      item_id: item.ItemID
    });
  }
}

// NOW sort + re-letter
products.sort((a, b) => {
  const kgA = extractKg(a.name);
  const kgB = extractKg(b.name);
  if (kgA !== kgB) return kgA - kgB;
  return a.name.localeCompare(b.name);
});

for (let i = 0; i < products.length; i++) {
  products[i].letter = letters[i % 26];
}

// Create formatted list for display
let formattedList = "📦 *Available Products:*\n\n";
for (const product of products) {
  formattedList += `*${product.letter}.* ${product.name}\n`;
  formattedList += `   🏷 R${product.price.toFixed(2)}\n\n`;
}

// Prepend ordering instructions
const orderInstructions =
"============================\n" +
"🚨 *IMPORTANT – Read Carefully Before Placing an Order* \n" +
"============================\n\n" +
"📝 *How to order:*\n" +
"Reply with the Letter in front of the item followed by the quantity.\n\n" +
"*Example:*\n" +
"B2\n" +
"D1\n" +
"(product B x 2 and product D x 1)\n\n";

formattedList = orderInstructions + formattedList;

return {
  success: true,
  total_products: products.length,
  products,
  formatted_list: formattedList
};

// =====================================================================
// PARSE AVAILABLE SLOTS - NEW TIMESLOT SYSTEM
// Groups by Date + Timeslot, counts availability, applies time-of-day rules
// =====================================================================

const now = new Date();
const endDate = new Date(now);
endDate.setDate(endDate.getDate() + 7); // Look 7 days ahead

console.log("📅 Looking for slots from now until:", endDate.toISOString().split('T')[0]);

// Get all rows from sheet
const allRows = $input.all().map(item => item.json);

console.log("📊 Total rows from sheet:", allRows.length);

// Group slots by Date + Timeslot
const timeslotGroups = {};
let processedRows = 0;

for (const row of allRows) {
  // Skip if no date or timeslot
  if (!row.delivery_date || !row.delivery_time) {
    continue;
  }

  // Skip if customer_name is filled (slot is booked)
  if (row.customer_name && row.customer_name.trim() !== '') {
    continue;
  }

  // Parse the date
  const slotDate = new Date(row.delivery_date + 'T00:00:00');

  // Skip if date is invalid or in the past
  if (isNaN(slotDate) || slotDate < now.setHours(0, 0, 0, 0)) {
    continue;
  }

  // Skip if beyond 7 days
  if (slotDate > endDate) {
    continue;
  }

  // Create key for this date+timeslot combo
  const key = `${row.delivery_date}|${row.delivery_time}`;

  if (!timeslotGroups[key]) {
    timeslotGroups[key] = {
      date: row.delivery_date,
      timeslot: row.delivery_time,
      available_count: 0,
      first_row_index: row.row_number
    };
  }

  timeslotGroups[key].available_count++;
  processedRows++;
}

console.log("✅ Processed rows:", processedRows);
console.log("📦 Timeslot groups found:", Object.keys(timeslotGroups).length);

// Convert to array and filter out fully booked timeslots
let availableTimeslots = Object.values(timeslotGroups)
  .filter(ts => ts.available_count > 0)
  .sort((a, b) => {
    if (a.date !== b.date) return a.date.localeCompare(b.date);
    return a.timeslot.localeCompare(b.timeslot);
  });

console.log("📋 Available timeslots before time-of-day filter:", availableTimeslots.length);

// ===== TODAY RULES =====
const nowTime = new Date();
const todayISO = nowTime.toISOString().split("T")[0];
const hour = nowTime.getHours();

console.log("⏰ Current hour:", hour);
console.log("📅 Today ISO:", todayISO);

// Normalize date format
function normalize(d) {
  return new Date(d + 'T00:00:00').toISOString().split("T")[0];
}

// Check if we have any slots for today
const hasToday = availableTimeslots.some(s => normalize(s.date) === todayISO);

// TODAY + BEFORE 12PM → Keep: Today PM + Tomorrow AM
if (hasToday && hour < 12) {
  console.log("📌 TODAY BEFORE 12PM: Showing today PM + tomorrow AM");
  const tomorrowISO = new Date(Date.now() + 86400000).toISOString().split("T")[0];

  availableTimeslots = availableTimeslots.filter(s => {
    const slotISO = normalize(s.date);

    return (
      // today afternoon
      (slotISO === todayISO && s.timeslot === '13:00-16:30') ||
      // tomorrow morning
      (slotISO === tomorrowISO && s.timeslot === '08:00-12:00')
    );
  });
}

// TODAY + AFTER 12PM → Keep: Tomorrow AM + Tomorrow PM
if (hasToday && hour >= 12) {
  console.log("📌 TODAY AFTER 12PM: Showing tomorrow only");
  const tomorrowISO = new Date(Date.now() + 86400000).toISOString().split("T")[0];

  availableTimeslots = availableTimeslots.filter(s => {
    const slotISO = normalize(s.date);
    return slotISO === tomorrowISO;
  });
}

console.log("📋 Available timeslots after time-of-day filter:", availableTimeslots.length);

// Separate morning and afternoon slots
const morningSlots = availableTimeslots.filter(s => s.timeslot === '08:00-12:00').slice(0, 2);
const afternoonSlots = availableTimeslots.filter(s => s.timeslot === '13:00-16:30').slice(0, 2);

console.log("🌅 Morning slots:", morningSlots.length);
console.log("☀️ Afternoon slots:", afternoonSlots.length);

// Format for display with letters A, B, C, D
let slotOptions = [];
let slotText = 'Next Available delivery slots:\n\n';
const letters = ['A', 'B'];
let letterIndex = 0;

if (morningSlots.length > 0) {
  slotText += '🌅 *Morning Slots (08:00-12:00):*\n';
  for (const slot of morningSlots) {
    const slotDate = new Date(slot.date + 'T00:00:00');
    const formattedDate = slotDate.toLocaleDateString('en-ZA', { 
      weekday: 'long', 
      day: 'numeric', 
      month: 'long',
      year: 'numeric'
    });

    const availText = slot.available_count === 1 ? '1 slot available' : `${slot.available_count} slots available`;

    slotOptions.push({
      letter: letters[letterIndex],
      date: slot.date,
      timeslot: slot.timeslot,
      time: slot.timeslot, // For backward compatibility
      available_count: slot.available_count,
      display: `${formattedDate} - Morning (08:00-12:00) - ${availText}`,
      row_index: slot.first_row_index
    });
    slotText += `${letters[letterIndex]} - ${formattedDate} - ${availText}\n`;
    letterIndex++;
  }
  slotText += '\n';
}

if (afternoonSlots.length > 0) {
  slotText += '☀️ *Afternoon Slots (13:00-16:30):*\n';
  for (const slot of afternoonSlots) {
    const slotDate = new Date(slot.date + 'T00:00:00');
    const formattedDate = slotDate.toLocaleDateString('en-ZA', { 
      weekday: 'long', 
      day: 'numeric', 
      month: 'long',
      year: 'numeric'
    });

    const availText = slot.available_count === 1 ? '1 slot available' : `${slot.available_count} slots available`;

    slotOptions.push({
      letter: letters[letterIndex],
      date: slot.date,
      timeslot: slot.timeslot,
      time: slot.timeslot, // For backward compatibility
      available_count: slot.available_count,
      display: `${formattedDate} - Afternoon (13:00-16:30) - ${availText}`,
      row_index: slot.first_row_index
    });
    slotText += `${letters[letterIndex]} - ${formattedDate} - ${availText}\n`;
    letterIndex++;
  }
}

if (slotOptions.length === 0) {
  slotText = '⚠️ No available slots in the next 7 days. Please contact us to arrange a delivery time.';
} else {
  slotText += '\nReply with A or B for your preferred slot, or type a different date to find the closest available slots to it.\nExample:\n25/01/2026 (use this format)';
}

console.log("✅ Final slot options:", slotOptions.length);

return {
  success: true,
  has_available_slots: slotOptions.length > 0,
  available_slots: slotOptions,
  morning_slots: morningSlots,
  afternoon_slots: afternoonSlots,
  formatted_slots: slotText,
  total_available: availableTimeslots.length,
  total_morning: morningSlots.length,
  total_afternoon: afternoonSlots.length
};

const phoneNumber = $input.item.json.phone_number;
const sessionDate = $input.item.json.session_date;

return {
  action: 'get',
  phone_number: phoneNumber,
  session_date: sessionDate
};

const messageData = $('Extract Message Data').item.json;
const stateData = $input.item.json.current_state || { current_step: $input.first().json.current_step };

return {
  message: messageData.message_text,
  current_step: stateData.current_step || $input.first().json.current_step,
  customer_type: stateData.customer_type || $input.first().json.customer_type,
  phone_number: messageData.phone_number
};

// ===== STATE MACHINE CONTROLLER - Updated Version =====

const intent = $input.item.json.intent || 'unclear';
const currentStep = $('Store Current State').item.json.current_step || 'initial';
const state = $('Store Current State').item.json || {};
const messageData = $('Extract Message Data').item.json;
const extractedData = $input.item.json.extracted_data || {};

// ===== STATE MACHINE DEFINITION =====
const stateMachine = {
  'initial': {
    '_default': {
      next_step: 'checking_customer',
      action: 'check_customer',
      response_template: null
    }
  },

  // === Awaiting Order Choice ===
  'awaiting_order_choice': {
    'repeat_order': {
      next_step: 'awaiting_address_choice',
      action: 'confirm_current_address',
      response_template: null
    },
    'new_order': {
      next_step: 'showing_products',
      action: 'get_product_catalog',
      response_template: null
