const inputData = $input.item.json;
const message = inputData.message?.toString().toLowerCase().trim() || '';
const currentStep = inputData.current_step || 'initial';

let intent = 'unclear';
let action = null;
let extractedData = {};
let confidence = 1.0;

console.log('🔍 Detecting intent for message:', message);
console.log('🔍 Current step:', currentStep);

// ===== Pattern matching by current step =====
if (currentStep === 'initial') {
  intent = 'greeting';

} else if (currentStep === 'awaiting_order_choice') {
  if (message === '1' || message.includes('repeat')) {
    intent = 'repeat_order';
    action = 'confirm_current_address';
  } else if (message === '2' || message.includes('different') || message.includes('new')) {
    intent = 'new_order';
    action = 'get_product_catalog';
  }

} else if (currentStep === 'new_order_clarification') {
  if (message === '1' || message.includes('keep')) {
    intent = 'keep_order';
    action = 'confirm_current_address';
  } else if (message === '2' || message.includes('new')) {
    intent = 'new_order';
    action = 'get_product_catalog';
  }

} else if (currentStep === 'confirm_new_details') {
  const m = message.trim().toLowerCase();

  if (m === 'y') {
    intent = 'current_details';
    action = 'get_product_catalog';
  } 
  else if (m === 'n') {
    intent = 'new_details';
    action = 'awaiting_new_customer_details'; // matches YOUR logic
  } 
  else {
    intent = 'unclear';
  }

} else if (currentStep === 'collecting_order_details') {
  const rawMsg = (inputData.message ?? "").toString().trim();

  const parts = rawMsg
    .split(/[\n,]+/)
    .map(p => p.trim())
    .filter(Boolean);

  const tokenRe = /^[A-Z]\d+$/i;

  if (parts.length && parts.every(p => tokenRe.test(p))) {
    intent = 'collecting_order_details_provided';
    action = 'collecting_order_details';
    extractedData.raw_collecting_order_details = inputData.message;
    extractedData.order_tokens = parts.map(p => p.toUpperCase());
  } else {
    intent = 'unclear';
    action = 'clarify';
  }


} else if (currentStep === 'awaiting_address_choice') {
  const token = message.trim().toLowerCase().replace(/[^a-z]/g, '');

  if (token === 's' || token === 'y') {
    intent = 'same_address';
  } 
  else if (token === 'd' || token === 'n') {
    intent = 'different_address';
  } 
  else {
    intent = 'unclear';
  }

} else if (currentStep === 'awaiting_street_code') {
  if (message.length === 4) {
    intent = 'street_code_provided';
    extractedData.raw_street_code = inputData.message;
    console.log('📍 Street code captured:', extractedData.raw_street_code);
  } else {
    intent = 'unclear';
  }

} else if (currentStep === 'awaiting_new_address') {
  const m = message.trim();

  if (m === 'r') {
    intent = 'confirm_current_address';
    action = 'confirm_current_address';

  } else if (m.length > 10) {
    intent = 'address_provided';
    action = 'update_customer_address'; // or 'confirm_new_address' / your expected next step
    extractedData.raw_address = inputData.message;

  } else {
    intent = 'unclear';
    action = 'clarify_address';
  }

} else if (currentStep === 'awaiting_new_customer_details') {
  const m = message.trim(); // message is already lowercased

  if (m === 'r') {
    intent = 'recheck_current_address';
  } else if (m.length > 20) {
    intent = 'new_customer_details_provided';
    action = 'update_customer_details';
    extractedData.raw_new_customer_details = inputData.message;
    console.log('📍 New customer details captured:', extractedData.raw_new_customer_details);
  } else {
    intent = 'unclear';
  }

} else if (currentStep === 'awaiting_existing_customer_details') {
  const rawMsg = inputData.message?.toString() || "";
  const m = rawMsg.trim().toLowerCase();
  const lines = rawMsg.split("\n").map(l => l.trim()).filter(Boolean);

  // ===== Recheck current details shortcut =====
  if (m === 'r') {
    intent = 'recheck_current_details';
    action = 'recheck_current_details';
  } 
  else {
    // ===== Name must be first line, min 2 words =====
    const hasName = lines.length >= 1 && lines[0].split(" ").filter(Boolean).length >= 2;

    // ===== Address must be second line =====
    const addressLine = lines[1] || "";
    const hasAddress = addressLine.length >= 8;

    // ===== Email optional, third line only =====
    const emailLine = lines[2] && /@/.test(lines[2]) ? lines[2] : "";

    // ===== Require Name + Address only =====
    if (hasName && hasAddress) {
      intent = 'existing_customer_details_provided';
      action = 'update_customer_details';
      extractedData.raw_new_customer_details = rawMsg;

      console.log("📍 Parsed Name:", lines[0]);
      console.log("📍 Parsed Address:", addressLine);
      console.log("📍 Parsed Email:", emailLine);
    } 
    else {
      intent = 'unclear';
    }
  }


// ===== AWAITING SLOT SELECTION =====
} else if (currentStep === 'awaiting_slot_selection') {

  // First: Check predefined slot selection A–D
 // const slotMatch = message.match(/^[abcd]$/i);
  const slotMatch = message.match(/^[a-z]$/i);

  if (slotMatch) {
    intent = 'awaiting_slot_selection_provided';
    action = 'book_delivery_slot';
    extractedData.slot_letter = slotMatch[0].toUpperCase();

    return {
      intent,
      action,
      confidence,
      extracted_data: extractedData,
      original_message: inputData.message,
      current_step: currentStep,
      customer_type: inputData.customer_type,
      phone_number: inputData.phone_number,
      reasoning: 'User selected slot A–D'
    };
  }

  // -----------------------------------------------------
  // If not A–D → treat as CUSTOM DATE request
  // -----------------------------------------------------

  let clean = message
    .replace('@', ' ')
    .replace(/,/g, ' ')
    .replace(/\n/g, ' ')
    .replace(/\bat\b/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();

  const now = new Date();

  // ===== RELATIVE: TOMORROW =====
  if (clean.includes("TOMORROW")) {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    clean = d.toISOString().split("T")[0];
  } 
  // ===== RELATIVE: TODAY =====
  else if (clean.includes("TODAY")) {
    clean = now.toISOString().split("T")[0];
  }
  // ===== RELATIVE: WEEKDAY NAMES =====
  else {
    const weekdays = [
      "SUNDAY","MONDAY","TUESDAY","WEDNESDAY","THURSDAY","FRIDAY","SATURDAY"
    ];
    const daysShort = ["SUN","MON","TUE","WED","THU","FRI","SAT"];

    let found = weekdays.find(w => clean.includes(w));
    if (!found) {
      const short = daysShort.find(s => clean.includes(s));
      if (short) found = weekdays[daysShort.indexOf(short)];
    }

    if (found) {
      const idx = weekdays.indexOf(found);
      const d = new Date();
      const diff = (idx + 7 - d.getDay()) % 7 || 7;
      d.setDate(d.getDate() + diff);
      clean = d.toISOString().split("T")[0];
    }
  }

  // ===== DATE EXTRACTION =====
  let dateMatch = clean.match(
    /(\d{4}[-\/\.]\d{1,2}[-\/\.]\d{1,2})|(\d{1,2}[-\/\.]\d{1,2}[-\/\.]\d{4})/
  );

  if (!dateMatch) {
    // Not A–D, not a valid date → unclear
    intent = 'unclear';
    action = 'clarify';

    return {
      intent,
      action,
      confidence,
      extracted_data: extractedData,
      original_message: inputData.message,
      current_step: currentStep,
      customer_type: inputData.customer_type,
      phone_number: inputData.phone_number,
      reasoning: 'Could not extract date or valid slot letter'
    };
  }

  // ===== NORMALIZE DATE FORMAT =====
  let datePart = dateMatch[0].replace(/[\/\.]/g, '-');
  const parts = datePart.split('-');

  let yyyy, mm, dd;
  if (parts[0].length === 4) {
    [yyyy, mm, dd] = parts;      // YYYY-MM-DD
  } else {
    [dd, mm, yyyy] = parts;      // DD-MM-YYYY
  }

  const normalizedDate =
    `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;

  extractedData.raw_date = normalizedDate;

  // Valid custom date
  intent = 'awaiting_custom_slot_selection_provided';
  action = 'check_custom_slot';

  return {
    intent,
    action,
    confidence,
    extracted_data: extractedData,
    original_message: inputData.message,
    current_step: currentStep,
    customer_type: inputData.customer_type,
    phone_number: inputData.phone_number,
    reasoning: 'User sent valid custom date'
  };

} else if (currentStep === 'awaiting_payment_confirmation') {
  if (message === 'p' || message.includes('pay')) {
    intent = 'confirm_payment';
     } else if (message === 'd' || message.includes('new')) {
    intent = 'new_order';
    action = 'get_product_catalog';
  } else if (message === 'cancel' || message.includes('cancel')) {
    intent = 'cancel_order';
  }
}

// ===== Global cancel/reset handlers =====
if (message.includes('cancel') || message.includes('stop') || message.includes('reset')) {
  intent = 'cancel_order';
  action = 'cancel_order';
}

console.log('✅ Detected intent:', intent);
console.log('⚡ Action:', action);

return {
  intent,
  action,
  confidence,
  extracted_data: extractedData,
  original_message: inputData.message,
  current_step: currentStep,
  customer_type: inputData.customer_type,
  phone_number: inputData.phone_number,
  reasoning: `Pattern matched for step: ${currentStep}`
};

// ===== PREPARE STATE FOR DATA TABLE SAVE =====
const phoneNumber = $('Extract Message Data').first().json.phone_number;
const sessionDate = $('Extract Message Data').first().json.session_date;
const sessionKey = `${phoneNumber}:${sessionDate}`;

console.log('💾 UPDATE STATE - Session key:', sessionKey);

// Helper: normalise codes (removes \n, tabs, double spaces, trailing spaces)
const normCode = (v) => String(v ?? '')
  .replace(/\s+/g, ' ')
  .trim();

// Get current state
const currentState = $('Parse State').first().json;

// Get the action result from merge
const actionResult = $('Merge All Responses').first().json;

console.log('🔍 Action result:', JSON.stringify(actionResult, null, 2));

// ===== Load recipe + Xero lookup maps (from state first, then optional node) =====
let product_recipes =
  currentState?.product_recipes ||
  (() => {
    try { return JSON.parse(currentState?.state_data || '{}')?.product_recipes || {}; }
    catch { return {}; }
  })();

let xero_items_by_code =
  currentState?.xero_items_by_code ||
  (() => {
    try { return JSON.parse(currentState?.state_data || '{}')?.xero_items_by_code || {}; }
    catch { return {}; }
  })();

// ---- get maps from node (ONLY if non-empty) ----
try {
  const maps = $items("Build Recipes + Xero Lookup Maps");
  const m = maps?.[0]?.json || {};

  const pr = m.product_recipes;
  const xb = m.xero_items_by_code;

  if (pr && typeof pr === 'object' && Object.keys(pr).length) product_recipes = pr;
  if (xb && typeof xb === 'object' && Object.keys(xb).length) xero_items_by_code = xb;
} catch (e) {
  console.log("ℹ️ Build Recipes + Xero Lookup Maps not available in this route.");
}

console.log("📦 product_recipes keys:", Object.keys(product_recipes || {}).length);
console.log("📦 xero_items_by_code keys:", Object.keys(xero_items_by_code || {}).length);

// ===== Gather order data safely =====
let orderItems = [];

try {
  const data = $items("Get row(s)");
  if (Array.isArray(data) && data.length > 0 && data[0].json) {
    orderItems = data.map(item => item.json);
  } else {
    console.log("ℹ️ 'Get row(s)' executed but returned no usable data.");
  }
} catch (e) {
  console.log("ℹ️ Skipping 'Get row(s)' – not executed in this branch.");
}

// ======================================================================
// Build JSON snapshots for payment + invoice (bundle-aware)
// Stores TWO fields into Conversation State:
// - order_summary_json (uses catalogue prices shown to customer)
// - invoice_lineitems_json (expands bundles using product_recipes + prices from xero_items_by_code)
// ======================================================================

let order_summary_json = '';
let invoice_lineitems_json = '';

if (orderItems.length > 0) {
  // A) order_summary_json (catalogue prices)
  const orderSummary = {
    currency: "ZAR",
    total: 0,
    lines: []
  };

  orderItems.forEach((item) => {
    let quantity = 1;
    if ($node["Parse Items and Quantities"] && $items("Parse Items and Quantities").length > 0) {
      const qtyMatch = $items("Parse Items and Quantities").find(q => q.json.letter === item.letter);
      if (qtyMatch && qtyMatch.json.quantity) quantity = Number(qtyMatch.json.quantity);
    }

    const unit = Number(item.price || 0);
    const total = Number((unit * quantity).toFixed(2));

    orderSummary.lines.push({
      letter: item.letter,
      code: normCode(item.code),
      label: String(item.name ?? '').trim(),
      qty: quantity,
      unit,
      total
    });

    orderSummary.total = Number((orderSummary.total + total).toFixed(2));
  });

  order_summary_json = JSON.stringify(orderSummary);

  // B) invoice_lineitems_json (bundle expansion + Xero pricing)
  const recipesOk = product_recipes && Object.keys(product_recipes).length > 0;
  const xeroOk = xero_items_by_code && Object.keys(xero_items_by_code).length > 0;

  if (!recipesOk || !xeroOk) {
    console.log("ℹ️ Skipping invoice_lineitems_json because product_recipes or xero_items_by_code is missing in state.");
  } else {
    // Expand selections using recipe components
    const expanded = []; // {ItemCode, Quantity}

    for (const item of orderItems) {
      let quantity = 1;
      if ($node["Parse Items and Quantities"] && $items("Parse Items and Quantities").length > 0) {
        const qtyMatch = $items("Parse Items and Quantities").find(q => q.json.letter === item.letter);
        if (qtyMatch && qtyMatch.json.quantity) quantity = Number(qtyMatch.json.quantity);
      }

      const displayCode = normCode(item.code);
      const recipe = product_recipes[displayCode];

      // If no recipe found, assume single = itself
      const components = Array.isArray(recipe?.components) && recipe.components.length
        ? recipe.components
        : [{ itemCode: displayCode, qty: 1 }];

      for (const c of components) {
        expanded.push({
          ItemCode: normCode(c.itemCode),
          Quantity: (Number(c.qty) || 1) * quantity
        });
      }
    }

    // Merge duplicates
    const qtyByCode = new Map();
    for (const l of expanded) {
      const c = normCode(l.ItemCode);
      const q = Number(l.Quantity ?? 0);
      if (!c || !q) continue;
      qtyByCode.set(c, (qtyByCode.get(c) || 0) + q);
    }

    // Build invoice lines from xero_items_by_code pricing/details
    const invoiceLines = [];
    const missingCodes = [];

    for (const [ItemCode, Quantity] of qtyByCode.entries()) {
      const x = xero_items_by_code[normCode(ItemCode)];

      if (!x) {
        missingCodes.push(ItemCode);
        continue;
      }

      const UnitAmount = Number(x?.SalesDetails?.UnitPrice ?? 0);
      const TaxType = String(x?.SalesDetails?.TaxType ?? "OUTPUT3");
      const AccountCode = String(x?.SalesDetails?.AccountCode ?? "200");
      const Description = String(x?.Name ?? x?.Description ?? ItemCode);
      const LineAmount = Number((UnitAmount * Quantity).toFixed(2));

      invoiceLines.push({
        ItemCode: normCode(ItemCode),
        Description,
        Quantity,
        UnitAmount,
        LineAmount,
        TaxType,
        AccountCode
      });
    }

    if (missingCodes.length) {
      console.log("❌ Missing Xero codes in xero_items_by_code:", missingCodes);
      invoice_lineitems_json = '';
    } else {
      invoice_lineitems_json = JSON.stringify(invoiceLines);
    }

    console.log("🧾 order_summary_json:", order_summary_json);
    console.log("🧾 invoice_lineitems_json:", invoice_lineitems_json);
  }
}

// ===== Preserve existing order data if not updating =====
// Try to get last_order from multiple sources
let existingOrder = currentState.last_order || {};

// For backward compatibility, try parsing from state_data if needed
try {
  const parsedStateData = JSON.parse(currentState.state_data || '{}');
  if (parsedStateData.last_order) {
    existingOrder = {
      ...parsedStateData.last_order,
      ...existingOrder  // Current takes precedence
    };
  }
} catch (e) {
  console.log('⚠️ Could not parse state_data:', e.message);
}

console.log('🔍 Existing order data loaded');

// Check for existing JSON fields at TOP LEVEL (new location)
console.log('🔍 Current state invoice_lineitems_json:', currentState.invoice_lineitems_json ? 'EXISTS' : 'EMPTY');
console.log('🔍 Current state order_summary_json:', currentState.order_summary_json ? 'EXISTS' : 'EMPTY');

// Only update invoice_lineitems_json and order_summary_json if we have new data
if (!invoice_lineitems_json && currentState.invoice_lineitems_json) {
  invoice_lineitems_json = currentState.invoice_lineitems_json;
  console.log("ℹ️ Preserving existing invoice_lineitems_json from top level");
}

if (!order_summary_json && currentState.order_summary_json) {
  order_summary_json = currentState.order_summary_json;
  console.log("ℹ️ Preserving existing order_summary_json from top level");
}

console.log('📋 After preservation - invoice_lineitems_json:', invoice_lineitems_json ? 'HAS DATA' : 'EMPTY');
console.log('📋 After preservation - order_summary_json:', order_summary_json ? 'HAS DATA' : 'EMPTY');

// ===== Build state updates =====
const stateUpdates = {
  current_step: actionResult.next_step || currentState.current_step,
  last_message: $('Extract Message Data').first().json.message_text,
  last_message_time: new Date().toISOString()
};

// ===== Merge optional updates =====
if (actionResult.state_updates) Object.assign(stateUpdates, actionResult.state_updates);
if (actionResult.customer_type !== undefined) stateUpdates.customer_type = actionResult.customer_type;

// ✅ APPLY MAPS LAST (prevents overwrite by state_updates) + never write empty over non-empty
const hasPR = product_recipes && Object.keys(product_recipes).length;
const hasXB = xero_items_by_code && Object.keys(xero_items_by_code).length;

if (hasPR) stateUpdates.product_recipes = product_recipes;
else if (currentState.product_recipes && Object.keys(currentState.product_recipes).length)
  stateUpdates.product_recipes = currentState.product_recipes;

if (hasXB) stateUpdates.xero_items_by_code = xero_items_by_code;
else if (currentState.xero_items_by_code && Object.keys(currentState.xero_items_by_code).length)
  stateUpdates.xero_items_by_code = currentState.xero_items_by_code;

// ===== Inject Xero customer data if available (POST-UPDATE) =====
try {
  const xeroContact =
    ($items('Get a contact')?.length > 0 ? $items('Get a contact')[0].json : null) ||
    ($items('Get Address')?.length > 0 ? $items('Get Address')[0].json : null) ||
    null;

  if (xeroContact) {
    const street = (xeroContact.Addresses || []).find(a => a.AddressType === 'STREET') || {};
    const deliveryAddress = [
      street.AddressLine1,
      street.AddressLine2,
      street.City,
      street.PostalCode,
    ].filter(Boolean).join(', ');

    stateUpdates.customer_data = {
      ...(stateUpdates.customer_data || {}),
      name: xeroContact.Name || '',
      email: xeroContact.EmailAddress || '',
      address: deliveryAddress || (stateUpdates.customer_data?.address || '')
    };

    if (deliveryAddress) stateUpdates.delivery_address = deliveryAddress;
  }
} catch (e) {
  console.log('ℹ️ No Xero contact data found for injection.');
}

if (actionResult.customer_data !== undefined) stateUpdates.customer_data = actionResult.customer_data;
if (actionResult.available_slots !== undefined) stateUpdates.available_slots = actionResult.available_slots;

// If we came from "Closest Available Slots", we get `suggestions` not `available_slots`.
if ((!stateUpdates.available_slots || stateUpdates.available_slots.length === 0)
  && Array.isArray(actionResult.suggestions)
  && actionResult.suggestions.length > 0) {

  stateUpdates.available_slots = actionResult.suggestions.map(s => ({
    letter: (s.label || s.letter || "").toString().toUpperCase(),
    date: s.date,
    time: s.time,
    display: `${s.date} - ${s.time}`,
    row_index: s.row_number ?? s.row_index
  })).filter(s => s.letter && s.row_index !== undefined);
}

if (actionResult.selected_slot !== undefined) stateUpdates.selected_slot = actionResult.selected_slot;
if (actionResult.order_id !== undefined) stateUpdates.order_id = actionResult.order_id;
if (actionResult.payment_url !== undefined) stateUpdates.payment_url = actionResult.payment_url;
if (actionResult.product_catalog !== undefined) stateUpdates.product_catalog = actionResult.product_catalog;

// ===== Calculate order total from order_summary_json =====
let orderTotal = 0;

if (order_summary_json) {
  try {
    const orderSummary = JSON.parse(order_summary_json);
    orderTotal = orderSummary.total || 0;
  } catch (e) {
    console.log('⚠️ Could not parse order_summary_json for total:', e.message);
  }
}

// ALWAYS preserve last_order, but only update with meaningful new data
// Start with existing order data as the base
stateUpdates.last_order = {
  ...(existingOrder || {}),  // Always start with existing data
};

// Check if we have any meaningful new order data
const hasNewInvoiceJson = invoice_lineitems_json && invoice_lineitems_json !== '';
const hasNewOrderJson = order_summary_json && order_summary_json !== '';
const hasNewOrderTotal = orderTotal > 0;

console.log('🔍 Has new data?', { hasNewInvoiceJson, hasNewOrderJson, hasNewOrderTotal });

// Only merge actionResult.last_order if it has meaningful data
if (actionResult.last_order !== undefined && actionResult.last_order !== null) {
  let hasMeaningfulActionResult = false;

  for (const [key, value] of Object.entries(actionResult.last_order || {})) {
    // Check if this is meaningful data
    const isMeaningful = 
      (key === 'order_total' && value > 0) ||
      (key === 'invoice_lineitems_json' && value && value !== '') ||
      (key === 'order_summary_json' && value && value !== '') ||
      (value !== undefined && value !== null && value !== '' && value !== 0);

    if (isMeaningful) {
      hasMeaningfulActionResult = true;
      stateUpdates.last_order[key] = value;
    }
  }

  if (hasMeaningfulActionResult) {
    console.log('✅ Merged meaningful data from actionResult.last_order');
  }
}

// Update order_total only if we have a new one
if (hasNewOrderTotal) {
  stateUpdates.last_order.order_total = Number(orderTotal.toFixed(2));
  console.log('✅ Updated order_total:', stateUpdates.last_order.order_total);
}

// ===== Move JSON snapshots to TOP LEVEL (not nested in last_order) =====
// This makes them persist like top-level columns
// Check both top-level (new) and last_order (old) for backward compatibility
if (hasNewInvoiceJson) {
  stateUpdates.invoice_lineitems_json = invoice_lineitems_json;
  console.log('✅ Updated invoice_lineitems_json at top level');
} else {
  // Preserve from either top-level or last_order (backward compatibility)
  const existingInvoice = currentState.invoice_lineitems_json || existingOrder.invoice_lineitems_json;
  if (existingInvoice) {
    stateUpdates.invoice_lineitems_json = existingInvoice;
    console.log('ℹ️ Preserved existing invoice_lineitems_json');
  }
}

if (hasNewOrderJson) {
  stateUpdates.order_summary_json = order_summary_json;
  console.log('✅ Updated order_summary_json at top level');
} else {
  // Preserve from either top-level or last_order (backward compatibility)
  const existingOrderSummary = currentState.order_summary_json || existingOrder.order_summary_json;
  if (existingOrderSummary) {
    stateUpdates.order_summary_json = existingOrderSummary;
    console.log('ℹ️ Preserved existing order_summary_json');
  }
}

console.log('📦 Final state will have invoice_lineitems_json:', stateUpdates.invoice_lineitems_json ? 'YES' : 'NO');
console.log('📦 Final state will have order_summary_json:', stateUpdates.order_summary_json ? 'YES' : 'NO');

console.log('🔍 State updates:', JSON.stringify(stateUpdates, null, 2));

// ===== Create updated state =====
const updatedState = {
  ...currentState,
  ...stateUpdates,
  last_updated: new Date().toISOString()
};

// ===== Add step history =====
if (actionResult.next_step && actionResult.next_step !== currentState.current_step) {
  if (!updatedState.step_history) updatedState.step_history = [];
  updatedState.step_history.push({
    from: currentState.current_step,
    to: actionResult.next_step,
    timestamp: new Date().toISOString()
  });
}

console.log('✅ State prepared for Data Table');

