  session_key: sessionKey,
  phone_number: phoneNumber,
  session_date: sessionDate,
  current_step: updatedState.current_step,
  customer_type: updatedState.customer_type || '',
  customer_data: JSON.stringify(updatedState.customer_data || {}),
  state_data: JSON.stringify(updatedState),
  last_updated: new Date().toISOString(),
  _row_id: currentState._row_id,
  _is_new: !currentState._row_id
};

// ===== PARSE STATE FROM DATA TABLE =====
