console.log('🔍 GET STATE - Session key:', sessionKey);

// Check if we got a row from Data Table
const tableRows = $input.all();

if (tableRows && tableRows.length > 0 && tableRows[0].json.state_data) {
  // Found existing state - PARSE THE JSON STRING
  try {
    const loadedState = JSON.parse(tableRows[0].json.state_data); // ← Parse string to object!
    console.log('✅ Loaded state from Data Table:', loadedState.current_step);

    return {
