// ===== CONFIRM CURRENT ADDRESS (Fetch from Xero) =====
const results = [];

for (const item of $input.all()) {
  let addressDisplay = '';
  let fullAddress = '';

  try {
    // Fetch directly from Xero contact result
    const xeroData = $('Get Address').first().json; // node returning contact info
    const addresses = xeroData?.Addresses || [];
    const street = addresses.find(a => a.AddressType === 'STREET') || addresses[0];

    if (street) {
      const parts = [];
      if (street.AddressLine1) parts.push(street.AddressLine1);
      if (street.AddressLine2) parts.push(street.AddressLine2);
      if (street.City) parts.push(street.City);
      if (street.PostalCode) parts.push(street.PostalCode);
      fullAddress = parts.join(', ');
      addressDisplay = fullAddress;
    } else {
      addressDisplay = 'No address on file in Xero';
    }
  } catch (err) {
    addressDisplay = 'Address data unavailable';
    console.error('❌ Failed to fetch Xero address:', err);
  }

  const response =
    `Great! Your delivery address on file is:\n\n*Address:* ${addressDisplay}\n\n` +
    `Would you like delivery to:\n` +
    `S - the same address\n` +
    `D - a different address?`;

  results.push({
    json: {
      response,
      next_step: 'awaiting_address_choice',
      state_updates: {
        delivery_address: fullAddress,
      },
    },
  });
}

return results;

// ===== ASK FOR NEW ADDRESS =====

const response = `Let's capture your new address.\n\n` +
                 `Please provide your full address, including the postal code in this format:\n` +
                 `Street address, Suburb, City, Postal code\n\n` +
                 `*Example:* \n` + 
                 `31 Example Road, Strand, Cape Town, 7140 \n\n` +
                 `*Or reply with:* \n` +
                 `R - to recheck your current address\n\n`
  ;

return {
  response: response,
  next_step: 'awaiting_new_address',
  state_updates: {}
};

const raw = $('Action Router (Switch)').first().json.extracted_data.raw_address || "";

// Address parser - New intelligent logic
function parseAddress(raw = "") {
  // Helper function to clean and normalize text
  function cleanText(text) {
    return text.trim().replace(/\s+/g, ' ');
  }

  // Helper function to check if a string is likely a postal code
  function isPostalCode(str) {
    return /^\d{4}$/.test(str.trim());
  }

  // Helper function to check if a string contains any number
  function hasNumber(str) {
    return /\d/.test(str);
  }

  // Split address by comma
  const parts = raw.split(',').map(part => cleanText(part)).filter(part => part.length > 0);

  let streetLine1 = '';
  let streetLine2 = '';
  let suburb = '';
  let city = '';
  let postalCode = '';

  if (parts.length === 0) {
    // Empty address
  } else {
    // Step 1: Working backwards, find 4-digit postal code
    let postalCodeIndex = -1;
    for (let i = parts.length - 1; i >= 0; i--) {
      if (isPostalCode(parts[i])) {
        postalCode = parts[i];
        postalCodeIndex = i;
        break;
      }
    }

    // Step 2: Working backwards from postal code, find first snippet with a number (last street line)
    let lastStreetIndex = -1;
    if (postalCodeIndex !== -1) {
      for (let i = postalCodeIndex - 1; i >= 0; i--) {
        if (hasNumber(parts[i])) {
          lastStreetIndex = i;
          break;
        }
      }
    }

    // Step 3: Check snippets between last street line and postal code
    if (lastStreetIndex !== -1 && postalCodeIndex !== -1) {
      const betweenCount = postalCodeIndex - lastStreetIndex - 1;

      if (betweenCount === 2) {
        // 2 snippets between: closest to code is City, next one is Suburb
        city = parts[postalCodeIndex - 1];
        suburb = parts[postalCodeIndex - 2];
      } else if (betweenCount === 1) {
        // Only 1 snippet: it's Suburb
        suburb = parts[postalCodeIndex - 1];
      }
      // If betweenCount is 0, no suburb/city (street line directly before postal code)

      // Step 4: Decide on street lines
      // All parts from beginning up to (but not including) suburb or postal code
      const endIndex = suburb ? parts.indexOf(suburb) : postalCodeIndex;
      const streetParts = parts.slice(0, endIndex);

      if (streetParts.length === 1) {
        // Only 1 snippet before suburb: it's streetLine1
        streetLine1 = streetParts[0];
      } else if (streetParts.length > 1) {
        // More than 1: closest to suburb is streetLine2, remainder is streetLine1
        streetLine2 = streetParts[streetParts.length - 1];
        streetLine1 = streetParts.slice(0, -1).join(', ');
      }
    } else if (parts.length > 0) {
      // Fallback: no clear structure found
      streetLine1 = parts[0];
    }
  }

  return { 
    streetLine1, 
    streetLine2, 
    suburb, 
    city, 
    postalCode 
  };
}

const parsed = parseAddress(raw);

return [
  {
    json: {
      AddressType: "STREET",
      AddressLine1: parsed.streetLine1 || "",
      AddressLine2: parsed.streetLine2 || "",
      City: parsed.city || parsed.suburb || "",
      Region: "",
      PostalCode: parsed.postalCode || "",
      Country: "South Africa"
    }
  }
];

