const postalFromState =
  (stateObj.postal_code && String(stateObj.postal_code).trim()) ||
  (/^\d{4}$/.test(String(stateObj.last_message || "").trim())
    ? String(stateObj.last_message).trim()
    : "");

// WhatsApp number
