      if (betweenCount === 2) {
        // 2 snippets between: closest to end is City, next one is Suburb
        city = parts[endPoint - 1];
        suburb = parts[endPoint - 2];
      } else if (betweenCount === 1) {
        // Only 1 snippet: it's City (or Suburb if no city concept)
        city = parts[endPoint - 1];
      }
      // If betweenCount is 0, no suburb/city (street line directly before postal code)

      // Step 4: Decide on street lines
      // All parts from beginning up to (but not including) suburb/city or postal code
      const locationIndex = suburb ? parts.indexOf(suburb) : (city ? parts.indexOf(city) : endPoint);
      const streetParts = parts.slice(0, locationIndex);

      if (streetParts.length === 1) {
        // Only 1 snippet before suburb/city: it's streetLine1
        streetLine1 = streetParts[0];
