      // Fallback: no clear structure found
      streetLine1 = parts[0];
      if (parts.length > 1) {
        city = parts[parts.length - 1];
      }
    }
  }

  return { 
    streetLine1, 
    streetLine2, 
    suburb, 
    city, 
    postalCode 
  };
}

const parsed = parseAddress(addressText, postalFromState);

