const NODE_PREP = "Prep Products";
const NODE_WL   = "Get Xero Whitelist Products";
const NODE_XERO = "Get Xero Products";

// ---------- 1) Read inputs safely ----------
const prep = (() => {
  try { return ($items(NODE_PREP) || []).map(i => i.json).filter(Boolean); }
  catch { return []; }
})();

const whitelistRows = (() => {
  try { return ($items(NODE_WL) || []).map(i => i.json).filter(Boolean); }
  catch { return []; }
})();

const xeroItems = (() => {
  try {
    const payload = ($items(NODE_XERO) || [])[0]?.json;
    return Array.isArray(payload?.Items) ? payload.Items : [];
  } catch {
    return [];
  }
})();

// ---------- 2) Build whitelist map (enabled only) ----------
const wlByCode = new Map(
  whitelistRows
    .filter(r => String(r.enabled).toUpperCase() === "TRUE" || r.enabled === true)
    .map(r => [String(r.code || "").trim(), r])
);

// ---------- 3) Build product_recipes (by DISPLAYED code) ----------
const product_recipes = {}; // { "LPG/5 KG New": { type, components:[{itemCode, qty}] } }

for (const p of prep) {
  const displayCode = String(p.code || "").trim();
  if (!displayCode) continue;

  const wl = wlByCode.get(displayCode);
  const type = String(wl?.type || "single").toLowerCase();

  if (type === "bundle") {
    let comps = [];
    try { comps = JSON.parse(wl?.components_json || "[]"); } catch { comps = []; }

    // normalise component keys
    const norm = comps
      .map(c => ({
        itemCode: String(c.itemCode || c.ItemCode || c.code || "").trim(),
        qty: Number(c.qty ?? c.Qty ?? c.quantity ?? 1) || 1,
      }))
      .filter(c => c.itemCode);

    product_recipes[displayCode] = { type: "bundle", components: norm.length ? norm : [{ itemCode: displayCode, qty: 1 }] };
  } else {
    product_recipes[displayCode] = { type: "single", components: [{ itemCode: displayCode, qty: 1 }] };
  }
}

// ---------- 4) Build xero_items_by_code (REAL Xero item code -> pricing/details) ----------
const xero_items_by_code = {}; // { "GAS-5KG": {UnitPrice,...}, ... }

for (const x of xeroItems) {
  const code = String(x?.Code || "").trim();
  if (!code) continue;

  xero_items_by_code[code] = {
    Code: code,
    Name: x?.Name || "",
    Description: x?.Description || "",
    SalesDetails: {
      UnitPrice: Number(x?.SalesDetails?.UnitPrice ?? 0),
      TaxType: String(x?.SalesDetails?.TaxType ?? ""),
      AccountCode: String(x?.SalesDetails?.AccountCode ?? ""),
    },
    ItemID: x?.ItemID || "",
  };
}

