for (const row of allRows) {
  // Skip header row or rows without dates
  if (!row['delivery_date'] || row['delivery_date'] === 'delivery_date') {
    currentRowNumber++;
    continue;
  }

  // Skip if Full Name is filled (slot is booked)
  if (row['customer_name'] && row['customer_name'].trim() !== '') {
    currentRowNumber++;
    continue;
  }

  // Parse the date
  const slotDate = new Date(row['delivery_date']);

  // Skip if date is invalid or in the past
  if (isNaN(slotDate) || slotDate < now) {
    currentRowNumber++;
    continue;
  }

  // Skip if beyond 7 days
  if (slotDate > endDate) {
    currentRowNumber++;
    continue;
  }

  // Parse time - handle both "9.30.00 AM" and "10:00 AM" formats
  let timeSlot = row['delivery_time'];
  if (!timeSlot) {
    currentRowNumber++;
    continue;
  }

  // Normalize time format
  timeSlot = timeSlot.toString().trim();

  // Determine if morning or afternoon
  const isMorning = timeSlot.toLowerCase().includes('am') || 
                   parseInt(timeSlot.split(/[:.]/)[0]) < 12;
  const isAfternoon = timeSlot.toLowerCase().includes('pm') || 
                     (parseInt(timeSlot.split(/[:.]/)[0]) >= 12 && parseInt(timeSlot.split(/[:.]/)[0]) < 18);

  // Format date nicely
  const formattedDate = slotDate.toLocaleDateString('en-ZA', { 
    weekday: 'long', 
    day: 'numeric', 
    month: 'long',
    year: 'numeric'
  });

  availableSlots.push({
    date: row['delivery_date'],
    time: timeSlot,
    formatted_date: formattedDate,
    is_morning: isMorning,
    is_afternoon: isAfternoon,
    row_index: currentRowNumber // Track actual row number for booking
  });

  currentRowNumber++;
}

// Sort by date and time
availableSlots.sort((a, b) => {
  const dateCompare = new Date(a.date) - new Date(b.date);
  if (dateCompare !== 0) return dateCompare;
  return a.time.localeCompare(b.time);
});

// ===== TODAY RULES =====
