  available_slots: slotOptions,
  morning_slots: morningSlots,
  afternoon_slots: afternoonSlots,
  formatted_slots: slotText,
  total_available: availableSlots.length,
  total_morning: morningSlots.length,
  total_afternoon: afternoonSlots.length
};

// ===== INPUT =====
const sheetData = $input.all().map(i => i.json);

// Extract the originally requested date
const requestedDate = $input.first().json.delivery_date ||
  $('State Machine Controller').first().json.extracted_data.raw_date ||
  '';

// Guard: if we don't have a requested date, we cannot look up slots
if (!requestedDate) {
  return {
    status: "none_available",
    message: "No delivery slots were found for that date.",
    requested_date: requestedDate || "",
    suggestions: []
  };
}

// Convert row → usable object
function mapRow(r, index) {
  return {
    row_number: r.row_number || index,
    date: r.delivery_date,
    time: r.delivery_time,
    isEmpty: !r.customer_name || r.customer_name.trim() === ""
  };
}

// Guard: only keep valid rows from the sheet
const rows = sheetData
  .filter(r => r.delivery_date && r.delivery_time)
  .map(mapRow);

// If sheet returned no usable rows, treat as none available for that date
if (rows.length === 0) {
  return {
    status: "none_available",
    message: "No delivery slots were found for that date.",
    requested_date: requestedDate,
    suggestions: []
  };
}

// ===== Find the FIRST row for the requested date =====
const requestedIndex = rows.findIndex(r => r.date === requestedDate);

// If date doesn't exist in sheet at all (e.g., Sunday excluded)
if (requestedIndex === -1) {
  return {
    status: "none_available",
    message: "No delivery slots were found for that date.",
    requested_date: requestedDate,
    suggestions: []
  };
}

// ===== Apply TODAY rules (time still used only here) =====
const now = new Date();
const todayStr = now.toISOString().split("T")[0];
const currentHour = now.getHours();

let usableRows = [...rows];

const isToday = requestedDate === todayStr;
const after12 = currentHour >= 12;

// RULE 1: Today + before noon → show only PM slots
if (isToday && !after12) {
  usableRows = usableRows.filter(r => {
    const h = new Date(`1970-01-01 ${r.time}`).getHours();
    return h >= 12;
  });
}

// RULE 2: Today + after noon → remove all today's slots
if (isToday && after12) {
  usableRows = usableRows.filter(r => r.date !== todayStr);
}

// Filter only rows matching the requested date
const dateMatches = usableRows.filter(r => r.date === requestedDate);

// Get only empty rows (available slots)
const available = dateMatches.filter(r => r.isEmpty);

if (available.length === 0) {
  return {
    status: "none_available",
    message: "No available delivery slots were found for that date.",
    requested_date: requestedDate,
    suggestions: []
  };
}

// Label as A, B, C, D ...
const suggestions = available.map((r, i) => ({
  label: String.fromCharCode(65 + i),
  date: r.date,
  time: r.time,
  row_number: r.row_number
}));

return {
  status: "alternatives_found",
  message: "Here are the available delivery slots for that date:",
  requested_date: requestedDate,
  suggestions
};

// ===== FORMAT MESSAGE INTO MORNING / AFTERNOON GROUPS =====
// ===== GET INPUT =====
const input = $input.first().json;
const suggestions = input.suggestions || [];

// Use requested_date from upstream when suggestions are empty (e.g., Sunday)
const requestedDate = input.requested_date || (suggestions.length > 0 ? suggestions[0].date : null);

// Convert YYYY-MM-DD → readable string
function formatDate(d) {
  const dateObj = new Date(d);
  return dateObj.toLocaleDateString("en-ZA", {
    weekday: "long",
    day: "2-digit",
    month: "long",
    year: "numeric"
  });
}

// Handle Sunday / date not in sheet / no slots returned
if (!suggestions.length) {
  const readableDate = requestedDate ? formatDate(requestedDate) : null;

  const messageText =
    readableDate
      ? `No delivery slots are available for *${readableDate}*.\n\n` +
        "Type a different date to find the closest available slots.\n" +
        "*Example:* 25/01/2026"
      : "No delivery slots found.\n\n" +
        "Type a different date to find the closest available slots.\n" +
        "*Example:* 25/01/2026";

  return [
    {
      response: messageText,
      suggestions: [],
      next_step: "awaiting_slot_selection"
    }
  ];
}

// Split AM / PM
const morning = suggestions.filter(s => {
  const hour = new Date(`1970-01-01 ${s.time}`).getHours();
  return hour < 12;
});

const afternoon = suggestions.filter(s => {
  const hour = new Date(`1970-01-01 ${s.time}`).getHours();
  return hour >= 12;
});

const readableDate = formatDate(requestedDate);

// Build final formatted message
let messageText = `Delivery slots available for *${readableDate}*: \n\n`;

if (morning.length > 0) {
  messageText += "🌅 *Morning Slots:*\n";
  morning.forEach(s => {
    messageText += `${s.label} - ${readableDate} - ${s.time}\n`;
  });
  messageText += "\n";
}

if (afternoon.length > 0) {
  messageText += "☀️ *Afternoon Slots:*\n";
  afternoon.forEach(s => {
    messageText += `${s.label} - ${readableDate} - ${s.time}\n`;
  });
  messageText += "\n";
}

messageText +=
  "Reply with the corresponding letter for your preferred slot, or type a different date to find the closest available slots.\n" +
  "*Example:* A  or  25/01/2026";

// 🔥 REQUIRED BY n8n → must return an ARRAY of objects
return [
  {
    response: messageText,
    suggestions,
    next_step: "awaiting_slot_selection"
  }
];

// Load state and controller data
const rawState = $('Store Current State').first().json.state_data;
const state = typeof rawState === "string" ? JSON.parse(rawState) : rawState;

const controllerData = $('State Machine Controller').item.json;
const extractedData = controllerData.extracted_data || {};

console.log("📥 Extracted Data:", extractedData);
console.log("📥 State Available Slots:", state.available_slots);
console.log("📥 Incoming JSON:", $json);

// =====================================================================
// SHARED FIELDS
// =====================================================================
const addressRaw = state.delivery_address || state.last_order?.delivery_address || "";

// Address parser - New intelligent logic
function parseAddress(raw = "") {
  // Helper function to clean and normalize text
  function cleanText(text) {
    return text.trim().replace(/\s+/g, ' ');
  }

  // Helper function to check if a string is likely a postal code
  function isPostalCode(str) {
    return /^\d{4}$/.test(str.trim());
  }

  // Helper function to check if a string contains any number
  function hasNumber(str) {
    return /\d/.test(str);
  }

  // Split address by comma
  const parts = raw.split(',').map(part => cleanText(part)).filter(part => part.length > 0);

  let streetLine1 = '';
  let streetLine2 = '';
  let suburb = '';
  let city = '';
  let postalCode = '';

  if (parts.length === 0) {
    // Empty address
  } else {
    // Step 1: Working backwards, find 4-digit postal code
    let postalCodeIndex = -1;
    for (let i = parts.length - 1; i >= 0; i--) {
      if (isPostalCode(parts[i])) {
        postalCode = parts[i];
        postalCodeIndex = i;
        break;
      }
    }

    // Step 2: Working backwards from postal code, find first snippet with a number (last street line)
    let lastStreetIndex = -1;
    if (postalCodeIndex !== -1) {
      for (let i = postalCodeIndex - 1; i >= 0; i--) {
        if (hasNumber(parts[i])) {
          lastStreetIndex = i;
          break;
        }
      }
    }

    // Step 3: Check snippets between last street line and postal code
    if (lastStreetIndex !== -1 && postalCodeIndex !== -1) {
      const betweenCount = postalCodeIndex - lastStreetIndex - 1;

      if (betweenCount === 2) {
        // 2 snippets between: closest to code is City, next one is Suburb
        city = parts[postalCodeIndex - 1];
        suburb = parts[postalCodeIndex - 2];
      } else if (betweenCount === 1) {
        // Only 1 snippet: it's Suburb
        suburb = parts[postalCodeIndex - 1];
      }
      // If betweenCount is 0, no suburb/city (street line directly before postal code)

      // Step 4: Decide on street lines
      // All parts from beginning up to (but not including) suburb or postal code
      const endIndex = suburb ? parts.indexOf(suburb) : postalCodeIndex;
      const streetParts = parts.slice(0, endIndex);

      if (streetParts.length === 1) {
        // Only 1 snippet before suburb: it's streetLine1
        streetLine1 = streetParts[0];
      } else if (streetParts.length > 1) {
        // More than 1: closest to suburb is streetLine2, remainder is streetLine1
        streetLine2 = streetParts[streetParts.length - 1];
        streetLine1 = streetParts.slice(0, -1).join(', ');
      }
    } else if (parts.length > 0) {
      // Fallback: no clear structure found
      streetLine1 = parts[0];
    }
  }

  return { 
    street1: streetLine1, 
    street2: streetLine2, 
    suburb: suburb, 
    city: city, 
    postal: postalCode 
  };
}

const parsedAddress = parseAddress(addressRaw);

const orderId = "ORD-" + new Date().toISOString().replace(/[-:T.]/g, "").slice(0, 14);

// PRODUCT DETAILS (shared)
let productDetails = "";
const customerName = $('Store Current State').first().json.full_name || state.customer_data?.name || "";

// Try order_summary_json first (top level)
const orderSummaryRaw = $('Store Current State').first().json.order_summary_json;
if (orderSummaryRaw) {
  try {
    const orderSummary = JSON.parse(orderSummaryRaw);
    const lines = orderSummary?.lines || orderSummary;
    if (Array.isArray(lines) && lines.length > 0) {
      productDetails = lines
        .map(p => `${p.qty || p.Quantity || 1} × ${p.label || p.Description || ""}`)
        .join(", ");
    }
  } catch (e) {
    console.log("⚠️ Could not parse order_summary_json:", e.message);
  }
}

// Fallback to last_order.products if order_summary_json not available
if (!productDetails) {
  if (Array.isArray(state.last_order?.products)) {
    productDetails = state.last_order.products
      .map(p => `${p.quantity || 1} × ${p.description || ""}`)
      .join(", ");
  }
}

// =====================================================================
// 1. CUSTOM SLOT HANDLING (from Edit Fields2)
// =====================================================================
const customRow = $json.custom_row_index;
const customDate = $json.custom_date;
const customTime = $json.custom_time;

if (customRow !== undefined && customDate && customTime) {
  console.log("📌 Using CUSTOM SLOT booking");

  return {
    row_number: customRow,
    delivery_date: customDate,
    delivery_time: customTime,
    customer_name: customerName,
    phone_number: state.phone_number,
    email: state.customer_data?.email || "",
    street_address_1: parsedAddress.street1 || "",
    street_address_2: parsedAddress.street2 || "",
    suburb: parsedAddress.suburb || "",
    city: parsedAddress.city || "",
    postal_code: parsedAddress.postal || "",
    order_id: orderId,
    product_details: productDetails,
    delivery_instructions: "",
  };
}

// =====================================================================
// 2. LETTER-BASED SLOT HANDLING (A/B/C/D)
// =====================================================================
if (extractedData.slot_letter) {
  const slotLetter = extractedData.slot_letter;
  console.log("📌 Using LETTER SLOT:", slotLetter);

  const selectedSlot = state.available_slots?.find(s =>
    (s.letter || s.label) === slotLetter
  );

  if (!selectedSlot) {
    throw new Error(`Slot ${slotLetter} not found in available slots`);
  }

  return {
    row_number: selectedSlot.row_index,
    delivery_date: selectedSlot.date,
    delivery_time: selectedSlot.time,
    customer_name: customerName,
    phone_number: state.phone_number,
    email: $input.first()?.json.state_data?.email || state.customer_data?.email || "",
    street_address_1: parsedAddress.street1 || "",
    street_address_2: parsedAddress.street2 || "",
    suburb: parsedAddress.suburb || "",
    city: parsedAddress.city || "",
    postal_code: parsedAddress.postal || "",
    order_id: orderId,
    product_details: productDetails,
    delivery_instructions: "",
  };
}

// =====================================================================
// 3. FALLBACK — NEITHER CUSTOM NOR LETTER SLOT PROVIDED
// =====================================================================
throw new Error("No valid slot information found (neither custom nor letter slot).");

// ===== FORMAT SLOTS RESPONSE =====
const slotsResult = $input.item.json;

console.log('📅 Slots result:', JSON.stringify(slotsResult, null, 2));

if (slotsResult.has_available_slots && slotsResult.available_slots) {
  console.log('✅ Found', slotsResult.available_slots.length, 'slots');

  return {
    response: slotsResult.formatted_slots,
    next_step: 'awaiting_slot_selection',
    state_updates: { 
      available_slots: slotsResult.available_slots // ← Save the slots array to state!
    }
  };
} else {
  console.log('❌ No available slots');

  return {
    response: '⚠️ No available slots in the next 7 days.\n\nPlease contact us to arrange a delivery time.',
    next_step: 'manual_booking_required',
    state_updates: {}
  };
}

